mockRegistry.register({
  id: 'visual-assets',
  description: 'Brand/school/conference SVG logos for the EntityAvatar component',
  load: () => VISUAL_ASSETS,
});

export function resolveAsset(id: string | undefined): VisualAsset | null {
  if (!id) return null;
  return VISUAL_ASSETS[id] ?? null;
}

/** Map a brand catalog id (br-nike) to the visual-assets id (brand-nike). */
export function brandAssetId(brandId: string): string {
  return brandId.startsWith('brand-') ? brandId : `brand-${brandId.replace(/^br-/, '')}`;
}

/** Map a school catalog id (sc-duke or school-duke) to the visual-assets id (school-duke). */
export function schoolAssetId(schoolId: string): string {
  if (schoolId.startsWith('school-')) return schoolId;
  return `school-${schoolId.replace(/^sc-/, '')}`;
}

/** Map a conference name to its visual-assets id. */
export function conferenceAssetId(conferenceName: string): string {
  const slug = conferenceName
    .toLowerCase()
    .replace(/\b(conference|the)\b/g, '')
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
  const map: Record<string, string> = {
    'sec': 'conference-sec',
    'southeastern': 'conference-sec',
    'big-ten': 'conference-big-ten',
    'big-10': 'conference-big-ten',
    'acc': 'conference-acc',
    'atlantic-coast': 'conference-acc',
    'big-12': 'conference-big-12',
    'big-east': 'conference-big-east',
    'aac': 'conference-aac',
    'american': 'conference-aac',
    'american-athletic': 'conference-aac',
    'meac': 'conference-meac',
    'mid-eastern-athletic': 'conference-meac',
    'swac': 'conference-swac',
    'southwestern-athletic': 'conference-swac',
  };
  return map[slug] ?? '';
}
